INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('promotion-6f0ba476-moex-00115', 'promotion-6f0ba476', 'promotion-6f0ba476-moex-112-e0b1f2ed', 'sub-promotion-6f0ba476-01', NULL, 'essay', '由於經營環境改變，丙公司認為玩具狗的生產設備價值可能發生減
損。該設備 X1 年 12 月 31 日之相關資料如下：成本$1,020,000，累
計折舊（截至 X1年底）$440,000，淨公允價值$295,000，預期未來現
金流入折現值（使用價值）$320,000，該設備預計尚可使用 5年，殘
值$20,000，使用年數合計法提列折舊。該設備至X2 年底仍未出售，
淨公允價值$340,000，預期未來現金流入折現值$325,000。
丙公司 X1年底有關的設備價值減損分錄為何？（7分）
丙公司 X2年底該設備應認列的減損迴轉利益為何？（8 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:29+00:00", "source_pdf_sha1": "f3d59328de4e", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "118", "s": "1002", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "會計學", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('promotion-6f0ba476-moex-00116', 'promotion-6f0ba476', 'promotion-6f0ba476-moex-112-e0b1f2ed', 'sub-promotion-6f0ba476-01', NULL, 'single_choice', '下列何者不屬於國際會計準則第40號的投資性不動產？', '["空置且將以一項或多項營業租賃出租之建築物", "正在建造或開發，以供未來作為投資性不動產使用之不動產", "以融資租賃出租予另一企業之不動產", "為獲取長期資本增值，而非供正常營業過程中短期內出售所持有之土地"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:29+00:00", "source_pdf_sha1": "f3d59328de4e", "answer_pdf_sha1": "a929678ff5f0", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "118", "s": "1002", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('promotion-6f0ba476-moex-00117', 'promotion-6f0ba476', 'promotion-6f0ba476-moex-112-e0b1f2ed', 'sub-promotion-6f0ba476-01', NULL, 'single_choice', '甲公司採用永續盤存制，並在8月份完成下列的交易： 賒銷 該批貨的銷貨退回 日期 金額 銷貨條件 日期 金額 收現日期 8月04日 $450 2/10,n/30 8月07日 8月07日 500 2/10,n/30 8月17日 8月11日 1,500 3/10,n/30 8月14日 $200 8月17日 8月13日 5,700 1/10,n/30 8月20日 1,200 8月25日 8月17日 3,200 2/15,n/60 8月28日 600 8月29日 8月23日 7,800 3/10,n/30 8月29日 1,900 8月31日 上表中「該批貨的銷貨退回」均為同一列賒銷交易所產生之銷貨退回，試計算甲公司8月份 自上述交易收現數總額：', '["$12,030", "$14,963", "$14,973", "$15,034"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:29+00:00", "source_pdf_sha1": "f3d59328de4e", "answer_pdf_sha1": "a929678ff5f0", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "118", "s": "1002", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('promotion-6f0ba476-moex-00118', 'promotion-6f0ba476', 'promotion-6f0ba476-moex-112-e0b1f2ed', 'sub-promotion-6f0ba476-01', NULL, 'single_choice', '甲公司採定期盤存制下的先進先出法（first-in,first-outmethod）計算存貨成本，X1年底期末 存貨$70,000，X2年底期末存貨$92,000，若改採加權平均法（weighted-average-costmethod） 計算期末存貨，則X1年度之毛利會減少$5,000，而X2年度之毛利會增加$6,000，試計算改 採加權平均法後，X2年底期末存貨成本：', '["$103,000", "$93,000", "$91,000", "$81,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:29+00:00", "source_pdf_sha1": "f3d59328de4e", "answer_pdf_sha1": "a929678ff5f0", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "118", "s": "1002", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('promotion-6f0ba476-moex-00119', 'promotion-6f0ba476', 'promotion-6f0ba476-moex-112-e0b1f2ed', 'sub-promotion-6f0ba476-01', NULL, 'single_choice', '甲畜牧公司於 X1 年購入一批小羊共 1,000 隻以供未來屠宰出售，每隻小羊之公允價值減銷 售費用為$2,050。X1年投入飼養該批小羊之飼料成本$95,000，相關人事成本$63,000。年底若 出售時每隻小羊估計市價約為$2,400，運送至肉品市場之費用約需$4,700。試計算期末報表中 應表達之生物資產金額：', '["$1,887,300", "$2,212,700", "$2,237,300", "$2,395,300"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:29+00:00", "source_pdf_sha1": "f3d59328de4e", "answer_pdf_sha1": "a929678ff5f0", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "118", "s": "1002", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('promotion-6f0ba476-moex-00120', 'promotion-6f0ba476', 'promotion-6f0ba476-moex-112-e0b1f2ed', 'sub-promotion-6f0ba476-01', NULL, 'single_choice', '甲公司於X1年7月1日以$270,000購入一台機器，估計耐用年限5年，殘值$20,000，使用 倍數餘額遞減法（2倍）與成本模式衡量提列折舊。X2年底由於經營環境改變，使得該機器 之價值有重大跡象顯示已經發生減損。甲公司於 X2 年底作減損測試，估計該機器之公允價 值減處分成本為$115,000，使用價值為$125,000，估計耐用年限不變。甲公司X2年應認列之 減損損失為：', '["$0", "$4,600", "$14,600", "$25,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:29+00:00", "source_pdf_sha1": "f3d59328de4e", "answer_pdf_sha1": "a929678ff5f0", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "118", "s": "1002", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('promotion-6f0ba476-moex-00121', 'promotion-6f0ba476', 'promotion-6f0ba476-moex-112-e0b1f2ed', 'sub-promotion-6f0ba476-01', NULL, 'single_choice', '甲公司於X1年10月1日以$94,500,000購買一筆土地，並支付土地過戶費$85,000，用以擴建 辦公空間。甲公司另支付$850,000將土地上的舊三合院拆除，並將殘料出售獲得現金$115,000。 此外，甲公司支付整地費$250,000、道路鋪設費$235,000、圍籬與照明設施$120,000、新辦公空 間的建築師設計費$580,000以及建造工程費$8,550,000。試計算該筆土地之入帳成本：', '["$94,585,000", "$95,570,000", "$95,685,000", "$105,055,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:29+00:00", "source_pdf_sha1": "f3d59328de4e", "answer_pdf_sha1": "a929678ff5f0", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "118", "s": "1002", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('promotion-6f0ba476-moex-00122', 'promotion-6f0ba476', 'promotion-6f0ba476-moex-112-e0b1f2ed', 'sub-promotion-6f0ba476-01', NULL, 'single_choice', '甲手機公司於X1年1月3日開始營業，當年出售新款智慧型手機5,000台，每台售價$36,900。 每台手機皆附有一年的售後服務保固。依同業經驗，1%的智慧型手機會發生重大瑕疵，2%的 智慧型手機會發生小瑕疵，重大瑕疵與小瑕疵的修理成本分別為每台$1,800與$500。該公司 X1年並未進行任何售後服務，試計算甲公司X1年應認列之售後服務保固費用：', '["$0", "$50,000", "$90,000", "$140,000"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:29+00:00", "source_pdf_sha1": "f3d59328de4e", "answer_pdf_sha1": "a929678ff5f0", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "118", "s": "1002", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('promotion-6f0ba476-moex-00123', 'promotion-6f0ba476', 'promotion-6f0ba476-moex-112-e0b1f2ed', 'sub-promotion-6f0ba476-01', NULL, 'single_choice', '甲公司X1年1月1日發行面額$100,000、票面利率12%的五年期公司債。該公司債有效利率為 10%，付息日為每年6月30日及12月31日。試計算該公司債理論發行價格：（現值因子或終值 因子請四捨五入至小數點後五位；發行價格四捨五入至整數位；請選擇最接近的答案）', '["$98,959", "$100,000", "$107,721", "$112,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:29+00:00", "source_pdf_sha1": "f3d59328de4e", "answer_pdf_sha1": "a929678ff5f0", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "118", "s": "1002", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('promotion-6f0ba476-moex-00124', 'promotion-6f0ba476', 'promotion-6f0ba476-moex-112-e0b1f2ed', 'sub-promotion-6f0ba476-01', NULL, 'single_choice', '甲公司於X1年2月3日以每股$14價格購入乙公司股票5,000股，並將之歸類為透過其他綜 合損益按公允價值衡量之權益投資。乙公司在 X1 年 6 月 12 日宣告並發放每股$1.3 現金股 利。X1年底乙公司股票價格為每股$17。該筆股票投資將使甲公司X1年之財務報表：', '["其他綜合損益增加$21,500", "本期淨利增加$21,500", "權益增加$15,000", "本期淨利增加$6,500"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:29+00:00", "source_pdf_sha1": "f3d59328de4e", "answer_pdf_sha1": "a929678ff5f0", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "118", "s": "1002", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "財稅行政"}'::jsonb, NULL)
